  description = 'A B-stance hinge that biases one hip while keeping enough support for meaningful sandbag loading.',
  card_summary = 'A B-stance hinge that biases one hip while keeping enough support for meaningful sandbag loading.',
  coach_language = 'Primary subrole: hinge_posterior_chain_strength. Strength is the main score. Explosiveness is secondary (1/5) only if coached with crisp intent, low fatigue, and adequate rest.',
  athlete_language = 'Move the load with control, stay braced, and finish every rep in the same shape you started.',
  movement_family = 'Sandbag Hinge Strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'hinge_posterior_chain_strength',
  primary_order_slot = 'staggered_stance_sandbag_rdl_strength',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = 30,
  default_rest_seconds = 90,
  est_seconds_per_set = 40,
  movement_requirements = '{"primary_joint_actions":["hip_hinge","hip_extension","spinal_bracing","trunk_bracing"],"primary_tissues":["gluteals","hamstrings","calves","foot_intrinsics","rectus_abdominis","obliques","spinal_erectors"],"primary_motor_control_demands":["bracing_under_load","postural_control","load_path_control"],"postural_shape":"loaded_strength_position","breathing_demand":"braced_breathing_without_panic_breath_hold","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"A B-stance hinge that biases one hip while keeping enough support for meaningful sandbag loading.","setup":["Select a sandbag load the athlete can control without rushing or changing position.","Grip or hug the sandbag so it stays close to the body before the first rep.","Clear the training lane and confirm the athlete understands the start and finish position.","Set ribs down, hips back, and lats engaged before moving the load."],"execution_steps":["Push hips back while keeping the load close.","Maintain a long spine and engaged lats.","Drive through the floor and finish with hips extended, not the low back arched."],"coach_cues":["Own the load before you move it.","Brace first, then rep.","Hips back, bag close.","Finish with glutes, not low back.","Get tight before the object leaves the floor."],"athlete_cues":["Strong shape first.","Move smooth, not rushed.","Stop before form changes."],"breathing_cues":["Inhale before the hardest position.","Brace as the load moves.","Reset breath between reps or short carry lengths."],"common_faults":["Chasing speed or fatigue instead of force quality.","Losing brace before the hardest part of the rep.","Rounding through the low back.","Letting the load drift away."],"quality_gate":["Athlete can explain and demonstrate the start and finish position.","Load path stays controlled without twisting or collapsing.","The last rep/step matches the first rep/step."],"stop_signs":["Pain, sharp discomfort, dizziness, or numbness.","Load cannot be controlled or set down safely.","Brace, posture, or alignment breaks for more than one rep/step.","Athlete rounds hard or twists unexpectedly while lifting from the floor."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Low-volume Output work","Sustained Capacity only after full recovery","Restore breathing or mobility"],"pairs_well_after":["General Raise Warm-Up","Dynamic Hip and T-Spine Access","Light Pattern Rehearsal"],"good_for_sessions":["general_warmup","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Do not use as a conditioning race or burnout finisher.","Do not place before freshness-sensitive Output work if the load is heavy.","Do not load through pain, unstable joints, or uncontrolled spinal position."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["NSCA Essentials of Strength Training and Conditioning - resistance training principles","Vortex exercise_card_details_for_llm.md - Card v2 authoring and Capacity phase logic"],"internal_notes":["Keep as strength-first capacity card; do not auto-classify as Output unless delivery, dose, and rest are rewritten.","Explosiveness score is intentionally secondary and delivery-dependent."]}'::jsonb,
  updated_at = now()
WHERE slug = 'staggered-stance-sandbag-rdl-strength';

